        for (char a : c.toCharArray()) {
            result = result.replace(String.valueOf(a), "");
        }
        return Arrays.asList(result, isPalindrome(result));
    }

    public boolean isPalindrome(String s) {
        int left = 0;
        int right = s.length() - 1;
        while (left < right) {
            if (s.charAt(left) != s.charAt(right)) {
                return false;
            }
            left++;
            right--;
        }
        return true;
    }
}

